import{_ as t,o as a,c as n,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Implement Content Security Protocol (CSP)","description":"","frontmatter":{"title":"Implement Content Security Protocol (CSP)","slug":"implement-content-security-protocol-csp"},"headers":[],"relativePath":"developer-hub/implement-content-security-protocol-csp.md","filePath":"developer-hub/implement-content-security-protocol-csp.md"}'),i={name:"developer-hub/implement-content-security-protocol-csp.md"};function o(c,e,r,p,l,h){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h2 id="background" tabindex="-1">Background <a class="header-anchor" href="#background" aria-label="Permalink to &quot;Background&quot;">​</a></h2><p>Branch takes customer’s privacy and security very seriously. The following document provides recommendations to enable our customers to implement Content Security Policy (CSP) in conjunction with the Branch webSDK into their websites.</p><h2 id="how-does-csp-work" tabindex="-1">How does CSP work <a class="header-anchor" href="#how-does-csp-work" aria-label="Permalink to &quot;How does CSP work&quot;">​</a></h2><p>Content Security Policy (CSP) is a computer security standard that provides an added layer of protection against Cross-Site Scripting (XSS), clickjacking, and other code injection attacks that rely on executing malicious content in the context of a trusted web page. By using suitable CSP directives in HTTP response headers, you can selectively specify which data sources should be permitted in your web application.</p><h3 id="add-csp-in-http-response-headers-on-server-side" tabindex="-1">Add CSP in HTTP response headers on Server Side <a class="header-anchor" href="#add-csp-in-http-response-headers-on-server-side" aria-label="Permalink to &quot;Add CSP in HTTP response headers on Server Side&quot;">​</a></h3><p>Any server side programming environment should allow you to send back a custom HTTP response header.Here’s an example of adding CSP headers to an Apache web server</p><p>Added to the httpd.conf or .htaccess file, this will set a default policy to allow only content from the origin.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Header set Content-Security-Policy &quot;default-src &#39;self&#39;;&quot;</span></span></code></pre></div><p>Please refer to <a href="https://content-security-policy.com/" target="_blank" rel="noreferrer">https://content-security-policy.com/</a> for different servers configuration.</p><h3 id="add-csp-through-meta-tag-under-html-page" tabindex="-1">Add CSP through <code>&lt;meta&gt;</code> tag under HTML Page <a class="header-anchor" href="#add-csp-through-meta-tag-under-html-page" aria-label="Permalink to &quot;Add CSP through \`&lt;meta&gt;\` tag under HTML Page&quot;">​</a></h3><p>CSP directive could be added on page level by using <code>&lt;meta&gt;</code> tag. Here is an example to add a CSP policy in your HTML page</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;meta http-equiv=&quot;Content-Security-Policy&quot; content=&quot;default-src &#39;self&#39;&quot;&gt;</span></span></code></pre></div><p>Both methods are widely adopted in the web. If your website is a single page application or you only want to apply the CSP to a specific page, adding CSP via <meta> header could be a better option as it is fast and easy to implement and change.</p><h2 id="integrate-the-branch-web-sdk-in-conjunction-with-csp-policy" tabindex="-1">Integrate the Branch Web SDK in conjunction with CSP policy <a class="header-anchor" href="#integrate-the-branch-web-sdk-in-conjunction-with-csp-policy" aria-label="Permalink to &quot;Integrate the Branch Web SDK in conjunction with CSP policy&quot;">​</a></h2><p>For customers having CSP policy implemented in its website or planning to add CSP policy when integrating Branch webSDK, here are some options and recommendations that we recommend.</p><h3 id="wrap-branch-related-code-into-a-local-javascript-file" tabindex="-1">Wrap Branch related code into a local javascript file <a class="header-anchor" href="#wrap-branch-related-code-into-a-local-javascript-file" aria-label="Permalink to &quot;Wrap Branch related code into a local javascript file&quot;">​</a></h3><p>If customers want to wrap and store the branch related JavaScript codes into a javascript file under the server where the website is hosted, they could use the <code>script-src &#39;self&#39;</code> policy as ‘self’ matches the current origin and JavaScript files loaded from the same origin will be allowed..</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Content-Security-Policy: script-src &#39;self&#39; https://cdn.branch.io https://app.link;</span></span></code></pre></div><p>Here is an example about adding a proper CSP policy with <meta> tag when integrating Branch webSDK using local javascript files. In the following script, the <strong>branch.js</strong> file is stored locally and <code>&amp;lt;meta http-equiv=&quot;Content-Security-Policy&quot; content=&quot;script-src &#39;self&#39; https://cdn.branch.io https://app.link&gt;</code> defines the CSP policy.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;!doctype html&gt;</span></span>
<span class="line"><span>&lt;html&gt;&lt;head&gt;</span></span>
<span class="line"><span>  &lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;</span></span>
<span class="line"><span>  &lt;meta http-equiv=&quot;Content-Security-Policy&quot; content=&quot;script-src &#39;self&#39; https://cdn.branch.io https://app.link&quot;&gt;</span></span>
<span class="line"><span>  &lt;title&gt;Branch Demo&lt;/title&gt;</span></span>
<span class="line"><span>  &lt;script src=&quot;branch.js&quot;&gt;&lt;/script&gt;</span></span>
<span class="line"><span>&lt;/head&gt;&lt;body&gt;Branch Journey Demo&lt;/body&gt;</span></span>
<span class="line"><span>&lt;/html&gt;</span></span></code></pre></div><h3 id="use-in-line-branch-related-javascript-codes" tabindex="-1"><code>Use in-line branch related javascript codes</code> <a class="header-anchor" href="#use-in-line-branch-related-javascript-codes" aria-label="Permalink to &quot;\`Use in-line branch related javascript codes\`&quot;">​</a></h3><p>Some customers prefer to use <a href="https://www.geeksforgeeks.org/how-does-inline-javascript-work-with-html/" target="_blank" rel="noreferrer">inline javascript</a> code when integrating with branchWebSDK. For example, our demo page <a href="https://cdn.us.document360.io/082e8be0-ad38-4650-9062-689a75e517a2/Images/Documentation/example(3).html" target="_blank" rel="noreferrer">https://cdn.branch.io/example.html</a> is using the inline script when calling functions defined in branchWebSDK.</p><p>There are two widely used options, using <em><strong>hashes</strong></em> or <strong>nonces</strong> to allow the executions of inline javascript codes securely when using CSP policy</p><h4 id="option-1-using-csp-hashes-policy-for-inline-script-security" tabindex="-1">Option 1: Using CSP hashes policy for inline script security <a class="header-anchor" href="#option-1-using-csp-hashes-policy-for-inline-script-security" aria-label="Permalink to &quot;Option 1: Using CSP hashes policy for inline script security&quot;">​</a></h4><p>Using a hash is one way to allow the execution of inline scripts in a Content Security Policy. It&#39;s simply a white list and when the browser sees that original script block it&#39;ll hash it, compare it with the CSP and then run it if it matches. Basically, the client hashes the inline javascript code and get a SHA256 hash and added it under the CSP policy</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Content-Security-Policy: script-src &#39;sha256-Ci5HNPYwBSR4VHU9hJh95ZFVy6fOb+k1oj6ZuaHln/g=&#39; https://cdn.branch.io https://app.link;</span></span></code></pre></div><p>Here is an example of using CSP hashes when using inline Javascript</p><p><a href="https://codepen.io/BranchWebSDK/pen/RwRqLmv" target="_blank" rel="noreferrer">https://codepen.io/BranchWebSDK/pen/RwRqLmv</a></p><p>In the code, we define the CSP hashes through the <meta> tag</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>…..</span></span>
<span class="line"><span>&lt;meta http-equiv=&quot;Content-Security-Policy&quot; content=&quot;script-src  &#39;sha256-Ci5HNPYwBSR4VHU9hJh95ZFVy6fOb+k1oj6ZuaHln/g=&#39; https://cdn.branch.io https://app.link&quot;&gt;</span></span>
<span class="line"><span>  &lt;title&gt;BranchWebSDK Demo&lt;/title&gt;</span></span>
<span class="line"><span>  &lt;script&gt;</span></span>
<span class="line"><span>    // load Branch</span></span>
<span class="line"><span>(function(b,r,a,n,c,h,_,s,d,k){if(!b[n]||!b[n]._q){for(;s&lt;_.length;)c(h,_[s++]);d=r.createElement(a);d.async=1;d.src=&quot;https://cdn.branch.io/branch-latest.min.js&quot;;</span></span>
<span class="line"><span>……</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre></div><p>The SHA256 hashes are generated based on the inline JavaScript code. The easiest way to generate it is to just open the developer tools console of your browsers and it will output what the expected hash of your script was in the console error message. Below is a screenshot of how browser console generate the CSP hashes for you.</p><p><em>[Image: 2418]</em></p><h4 id="option-2-using-csp-nonce-policy-for-inline-script-security" tabindex="-1">Option 2: Using CSP nonce policy for inline script security <a class="header-anchor" href="#option-2-using-csp-nonce-policy-for-inline-script-security" aria-label="Permalink to &quot;Option 2: Using CSP nonce policy for inline script security&quot;">​</a></h4><p>The biggest challenge for using hashes is that the hash has to be regenerated when you change your scripts. It means, if your inline JavaScript codes are dynamic, this hash method will not be useful for you. CSP nonce provides another way to handle it.</p><p>A nonce is a pseudo-random &quot;number used once&quot;. Rather than white listing a precise script block like the hash does, a nonce allows you to white list the entire script block regardless of what&#39;s in there.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Content-Security-Policy: script-src &#39;nonce-4AEemGb0xJptoIGFP3Nd&#39; https://cdn.branch.io https://app.link;</span></span></code></pre></div><p>Here is an example of <a href="https://codepen.io/BranchWebSDK/pen/LYZBqao" target="_blank" rel="noreferrer">https://codepen.io/BranchWebSDK/pen/LYZBqao</a> using nonce in CSP policy. In the codes, It consists of both a <code>&lt;meta&gt;</code> header with CSP policy defined and an attribute on the script tag</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;head&gt;</span></span>
<span class="line"><span>  &lt;meta http-equiv=&quot;Content-Security-Policy&quot; content=&quot;script-src  &#39;nonce-4AEemGb0xJptoIGFP3Nd&#39; https://cdn.branch.io https://app.link&quot;&gt;</span></span>
<span class="line"><span>  &lt;title&gt;BranchWebSDK Demo&lt;/title&gt;</span></span>
<span class="line"><span>  &lt;script nonce=&quot;4AEemGb0xJptoIGFP3Nd&quot;&gt;</span></span>
<span class="line"><span>    // load Branch</span></span>
<span class="line"><span>(function(b,r,a,n,c,h,_,s,d,k){if(!b[n]||!b[n]._q){for(;s&lt;_.length;)c(h,_[s++]);d=r.createElement(a);d.async=1;d.src=&quot;https://cdn.branch.io/branch-latest.min.js&quot;;k=r.getElementsByTagName(a)[0];k.parentNode.insertBefore(d,k);b[n]=h}})(window,document,&quot;script&quot;,&quot;branch&quot;,function(b,r)</span></span>
<span class="line"><span>……</span></span>
<span class="line"><span> &lt;/script&gt;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Note</p><p>The nonce should be generated per request, and it should be random.</p></div><p>In the above provided example, we explicitly added <code>script-src</code> because some javascript files are loaded from these two domains when executing the branch webSDK</p>`,40)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
